#!/usr/bin/env node
//
// Generates src/lib/generated/brandIcons.ts — a static map of brand icon
// SVG paths for use by PresetIcon.svelte. Replaces the `simple-icons`
// barrel import which added ~5MB to the bundle (tree-shaking fails on
// dynamic-key lookups like icons['si' + slug]).
//
// WHEN TO RUN:
//   1. You added a new preset in internal/singbox/router/internalpresets/data.go
//      that references a brand icon not yet in this map.
//   2. You need to update an icon to a newer simple-icons version.
//
// HOW TO RUN:
//   cd frontend
//   node scripts/generate-brand-icons.mjs
//   git add src/lib/generated/brandIcons.ts
//
// IF A NEW SLUG IS MISSING FROM simple-icons v16:
//   Add it to the MANUAL block below with {hex, path} copied from a
//   brand guidelines page or an older simple-icons version.
//
import { readFile, writeFile } from 'node:fs/promises';
import { fileURLToPath } from 'node:url';
import { dirname, resolve } from 'node:path';

