async function extractFromSimpleIcons(slug) {
	const svgPath = resolve(SI_DIR, 'icons', `${slug}.svg`);
	const svg = await readFile(svgPath, 'utf8');
	const pathMatch = svg.match(/<path\s+d="([^"]+)"/);
	if (!pathMatch) {
		throw new Error(`no path for ${slug}`);
	}
	return pathMatch[1];
}

async function buildMap() {
	const dataPath = resolve(SI_DIR, 'data/simple-icons.json');
	const data = JSON.parse(await readFile(dataPath, 'utf8'));
	const hexBySlug = new Map();
	for (const entry of data) {
		if (entry.slug) hexBySlug.set(entry.slug, entry.hex);
	}

	const out = {};
	for (const slug of SLUGS_FROM_SIMPLE_ICONS.sort()) {
		const path = await extractFromSimpleIcons(slug);
		const hex = hexBySlug.get(slug);
		if (!hex) throw new Error(`no hex for ${slug}`);
		out[slug] = { path, hex };
	}
	for (const [slug, entry] of Object.entries(MANUAL).sort(([a], [b]) => a.localeCompare(b))) {
		out[slug] = entry;
	}
	return out;
}

function serialize(map) {
	const lines = [
		'// Generated by scripts/generate-brand-icons.mjs. Do not edit by hand.',
		'// Regenerate after adding new preset brand icons.',
		'',
		'export interface BrandIcon {',
		'\tpath: string;',
		'\thex: string;',
		'}',
		'',
		'export const brandIcons: Record<string, BrandIcon> = {',
	];
	const entries = Object.entries(map).sort(([a], [b]) => a.localeCompare(b));
	for (const [slug, { path, hex }] of entries) {
		const safeSlug = /^[a-zA-Z_][a-zA-Z0-9_]*$/.test(slug) ? slug : JSON.stringify(slug);
		lines.push(`\t${safeSlug}: { hex: ${JSON.stringify(hex)}, path: ${JSON.stringify(path)} },`);
	}
	lines.push('};', '');
	return lines.join('\n');
}

const map = await buildMap();
await writeFile(OUT, serialize(map), 'utf8');
console.log(`wrote ${OUT} with ${Object.keys(map).length} brands`);
